import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>, label: String): Long {
    val N = n.toInt()
    val graph = Array(N) { mutableListOf<Int>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        graph[u].add(v)
        graph[v].add(u)
    }

    var ans = 1L
    val queue = LinkedList<State>()
    val seen = mutableSetOf<State>()
    val initialUnmatched = CharArray(N) { ' ' }

    for (i in 0 until N) {
        val mask = 1 shl i
        val u = i
        val v = i
        val c = label[i]
        val unmatched = c.toString()
        initialUnmatched[i] = c
        if (unmatched.length <= 1) {
            ans = maxOf(ans, 1)
        }
        val state = State(mask, u, v, unmatched)
        queue.add(state)
        seen.add(state)
    }

    while (queue.isNotEmpty()) {
        val (mask, u, v, unmatched) = queue.poll()

        for (next in graph[u]) {
            if (mask and (1 shl next) != 0) continue
            val newMask = mask or (1 shl next)
            val newSize = Integer.bitCount(newMask)
            val c = label[next]
            val newUnmatched = if (unmatched.isNotEmpty() && unmatched[0] == c) {
                unmatched.substring(1)
            } else {
                c.toString() + unmatched
            }

            if (newUnmatched.length > 2 * (N - newSize) + 1) {
                continue
            }

            if (newUnmatched.length <= 1) {
                ans = maxOf(ans, newSize.toLong())
            }

            val newState = State(newMask, next, v, newUnmatched)
            if (newState in seen) continue
            seen.add(newState)
            queue.add(newState)
        }

        for (next in graph[v]) {
            if (mask and (1 shl next) != 0) continue
            val newMask = mask or (1 shl next)
            val newSize = Integer.bitCount(newMask)
            val c = label[next]
            val newUnmatched = if (unmatched.isNotEmpty() && unmatched[unmatched.length - 1] == c) {
                unmatched.substring(0, unmatched.length - 1)
            } else {
                unmatched + c
            }

            if (newUnmatched.length > 2 * (N - newSize) + 1) {
                continue
            }

            if (newUnmatched.length <= 1) {
                ans = maxOf(ans, newSize.toLong())
            }

            val newState = State(newMask, u, next, newUnmatched)
            if (newState in seen) continue
            seen.add(newState)
            queue.add(newState)
        }
    }

    return ans
}

data class State(val mask: Int, val u: Int, val v: Int, val unmatched: String)
